// Define a struct to hold cache data
#[derive(Serialize, Deserialize)]
struct CacheData {
    user_preferences: UserPreferences,
}

fn save_cache(cache_path: &PathBuf, cache_data: &CacheData) -> io::Result<()> {
    let serialized_data = serialize(&cache_data).map_err(|e| e.into_io_error())?;
    fs::write(cache_path, serialized_data)
        .map_err(|e| e.into_io_error())?;
    Ok(())
}

fn load_cache(cache_path: &PathBuf) -> Result<CacheData, io::Error> {
    let data = fs::read(cache_path).map_err(|e| e.into_io_error())?;
    let cache_data = deserialize(&data).map_err(|e| e.into_io_error())?;
    Ok(cache_data)
}

